// N8N Code Node - Complete Campaign Data Extraction
// This code handles the LinkedIn campaign data from your Get Campaign Analytics node

// Handle different possible data structures in N8N
let campaigns = [];

// Check if data is coming as items array
if (items && items.length > 0) {
  campaigns = items;
} else if ($input && $input.all) {
  campaigns = $input.all();
} else if ($node && $node["Get Campaign Analytics1"] && $node["Get Campaign Analytics1"].json) {
  // If data is coming from a specific node
  campaigns = Array.isArray($node["Get Campaign Analytics1"].json) 
    ? $node["Get Campaign Analytics1"].json.map(item => ({ json: item }))
    : [{ json: $node["Get Campaign Analytics1"].json }];
} else if ($json) {
  // If there's a direct $json object
  campaigns = Array.isArray($json) 
    ? $json.map(item => ({ json: item }))
    : [{ json: $json }];
}

// If we have elements array in the data structure
if (campaigns.length === 1 && campaigns[0].json && campaigns[0].json.elements) {
  // Extract campaigns from elements array
  const elements = campaigns[0].json.elements;
  campaigns = elements.map(element => ({ json: element }));
}

// Process each campaign
return campaigns.map(campaign => {
  // Handle different data access patterns
  const data = campaign.json || campaign;

  // Safely handle missing data
  if (!data) {
    return {
      json: {
        error: "No campaign data found",
        originalData: campaign
      }
    };
  }

  // Convert timestamps to readable dates (handle missing runSchedule)
  const startDate = data.runSchedule?.start ? new Date(data.runSchedule.start) : null;
  const endDate = data.runSchedule?.end ? new Date(data.runSchedule.end) : null;

  // === EXTRACT TARGET AUDIENCE DETAILS ===
  const targetingCriteria = data.targetingCriteria?.include?.and || [];

  // Extract all targeting facets safely
  const targetAudience = {
    // Seniority Levels
    seniorities: targetingCriteria
      .find(criteria => criteria.or && criteria.or['urn:li:adTargetingFacet:seniorities'])
      ?.or?.['urn:li:adTargetingFacet:seniorities'] || [],

    // Job Titles
    titles: targetingCriteria
      .find(criteria => criteria.or && criteria.or['urn:li:adTargetingFacet:titles'])
      ?.or?.['urn:li:adTargetingFacet:titles'] || [],

    // Geographic Locations
    locations: targetingCriteria
      .find(criteria => criteria.or && criteria.or['urn:li:adTargetingFacet:locations'])
      ?.or?.['urn:li:adTargetingFacet:locations'] || [],

    // Company Size (Staff Count Ranges)
    staffCountRanges: targetingCriteria
      .find(criteria => criteria.or && criteria.or['urn:li:adTargetingFacet:staffCountRanges'])
      ?.or?.['urn:li:adTargetingFacet:staffCountRanges'] || [],

    // Industries
    industries: targetingCriteria
      .find(criteria => criteria.or && criteria.or['urn:li:adTargetingFacet:industries'])
      ?.or?.['urn:li:adTargetingFacet:industries'] || [],

    // Interface Locales (Language targeting)
    interfaceLocales: targetingCriteria
      .find(criteria => criteria.or && criteria.or['urn:li:adTargetingFacet:interfaceLocales'])
      ?.or?.['urn:li:adTargetingFacet:interfaceLocales'] || [],

    // Audience Expansion Setting
    audienceExpansionEnabled: data.audienceExpansionEnabled || false
  };

  // Count total targeting criteria
  const audienceTargetCount = {
    seniorities: targetAudience.seniorities.length,
    titles: targetAudience.titles.length,
    locations: targetAudience.locations.length,
    companies: targetAudience.staffCountRanges.length,
    industries: targetAudience.industries.length,
    locales: targetAudience.interfaceLocales.length
  };

  // Create a summary of active targeting
  const activeTargeting = Object.entries(audienceTargetCount)
    .filter(([key, value]) => value > 0)
    .map(([key, value]) => `${value} ${key}`)
    .join(', ');

  // === BUDGET INFORMATION ===
  const budget = {
    // Total Campaign Budget
    total: data.totalBudget ? {
      amount: data.totalBudget.amount || 0,
      currency: data.totalBudget.currencyCode || 'EUR',
      formatted: `${data.totalBudget.currencyCode || 'EUR'} ${data.totalBudget.amount || 0}`
    } : null,

    // Daily Budget
    daily: data.dailyBudget ? {
      amount: data.dailyBudget.amount || 0,
      currency: data.dailyBudget.currencyCode || 'EUR',
      formatted: `${data.dailyBudget.currencyCode || 'EUR'} ${data.dailyBudget.amount || 0}`
    } : null,

    // Unit Cost (CPC/CPM)
    unitCost: data.unitCost ? {
      amount: data.unitCost.amount || 0,
      currency: data.unitCost.currencyCode || 'EUR',
      formatted: `${data.unitCost.currencyCode || 'EUR'} ${data.unitCost.amount || 0}`,
      type: data.costType || 'Unknown'
    } : null,

    // Cost Type (CPC, CPM, etc.)
    costType: data.costType || 'Not specified'
  };

  // === SERVING STATUSES - Format for readability ===
  const servingStatusesFormatted = (data.servingStatuses || [])
    .map(status => {
      // Convert snake_case to readable format
      return String(status).replace(/_/g, ' ')
        .toLowerCase()
        .replace(/\b\w/g, char => char.toUpperCase());
    })
    .join(', ');

  // Format dates safely
  const formatDate = (date) => {
    if (!date) return 'Not set';
    try {
      return date.toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      });
    } catch (e) {
      return 'Invalid date';
    }
  };

  const formatSimpleDate = (date) => {
    if (!date) return 'Not set';
    try {
      return date.toLocaleDateString('en-US');
    } catch (e) {
      return 'Invalid date';
    }
  };

  return {
    json: {
      // === 1. CAMPAIGN NAME ===
      campaignName: data.name || 'Unnamed Campaign',

      // === 2. START DATE ===
      startDate: startDate ? {
        timestamp: data.runSchedule.start,
        iso: startDate.toISOString(),
        formatted: formatDate(startDate),
        simple: formatSimpleDate(startDate)
      } : {
        timestamp: null,
        iso: null,
        formatted: 'Not set',
        simple: 'Not set'
      },

      // End date for reference
      endDate: endDate ? {
        timestamp: data.runSchedule.end,
        iso: endDate.toISOString(),
        formatted: formatDate(endDate),
        simple: formatSimpleDate(endDate)
      } : {
        timestamp: null,
        iso: null,
        formatted: 'Not set',
        simple: 'Not set'
      },

      // === 3. COUNTRY ===
      country: {
        code: data.locale?.country || 'Not specified',
        language: data.locale?.language || 'Not specified',
        combined: data.locale ? `${data.locale.country} (${data.locale.language})` : 'Not specified'
      },

      // === 4. CAMPAIGN STATUS ===
      campaignStatus: data.status || 'Unknown',

      // === 5. SERVING STATUSES ===
      servingStatuses: {
        raw: data.servingStatuses || [],
        formatted: servingStatusesFormatted || 'No serving status',
        count: (data.servingStatuses || []).length,
        isActive: data.servingStatuses ? !data.servingStatuses.includes('STOPPED') : false
      },

      // === 6. OBJECTIVE TYPE ===
      objectiveType: data.objectiveType || 'Not specified',

      // === 7. TARGET AUDIENCE ===
      targetAudience: {
        // Full details
        details: targetAudience,

        // Summary info
        summary: {
          totalCriteria: activeTargeting || 'No specific targeting',
          audienceExpansion: targetAudience.audienceExpansionEnabled ? 'Enabled' : 'Disabled',
          criteriaCount: audienceTargetCount
        },

        // Quick reference lists
        quickView: {
          hasSeniorities: targetAudience.seniorities.length > 0,
          hasTitles: targetAudience.titles.length > 0,
          hasLocations: targetAudience.locations.length > 0,
          hasCompanySizes: targetAudience.staffCountRanges.length > 0,
          hasIndustries: targetAudience.industries.length > 0
        }
      },

      // === 8. BUDGET ===
      budget: {
        total: budget.total,
        daily: budget.daily,
        unitCost: budget.unitCost,
        costType: budget.costType,

        // Quick summary
        summary: {
          totalBudget: budget.total?.formatted || 'Not set',
          dailyBudget: budget.daily?.formatted || 'Not set',
          costModel: `${budget.costType} - ${budget.unitCost?.formatted || 'Not set'}`
        }
      },

      // === ADDITIONAL USEFUL FIELDS ===
      metadata: {
        campaignId: data.id || 'No ID',
        account: data.account || 'Not specified',
        organization: data.associatedEntity || 'Not specified',
        campaignGroup: data.campaignGroup || 'Not specified',
        format: data.format || 'Not specified',
        optimizationType: data.optimizationTargetType || 'None',
        createdAt: data.changeAuditStamps?.created?.time 
          ? new Date(data.changeAuditStamps.created.time).toISOString() 
          : 'Not available',
        lastModified: data.changeAuditStamps?.lastModified?.time 
          ? new Date(data.changeAuditStamps.lastModified.time).toISOString() 
          : 'Not available',
        versionTag: data.version?.versionTag || 'No version'
      },

      // === QUICK ACCESS SUMMARY ===
      summary: {
        name: data.name || 'Unnamed',
        status: `${data.status || 'Unknown'} (${servingStatusesFormatted || 'No status'})`,
        dates: `${formatSimpleDate(startDate)} - ${formatSimpleDate(endDate)}`,
        location: data.locale ? `${data.locale.country} (${data.locale.language})` : 'Not specified',
        objective: data.objectiveType || 'Not specified',
        budget: budget.total?.formatted || 'Not set',
        targeting: activeTargeting || 'No specific targeting'
      }
    }
  };
});
